content:
(["-map", "0:v"]);
        }

        match codec {
            OutputCodec::ProRes => {
                cmd.args([
                    "-c:v", "prores_ks",
                    "-profile:v", "3",     // 422 HQ
                    "-pix_fmt", "yuv422p10le",
                ]);
            }
            OutputCodec::Hevc10 => {
                // Try NVENC first
                static HEVC_NVENC_AVAILABLE: OnceLock<bool> = OnceLock::new();
                let nvenc = *HEVC_NVENC_AVAILABLE.get_or_init(|| {
                    Command::new("ffmpeg")
                        .args(["-hide_banner", "-encoders"])
                        .output()
                        .map(|o| String::from_utf8_lossy(&o.stdout).contains("hevc_nvenc"))
                        .unwrap_or(false)
                });
                if nvenc {
                    cmd.args([
                        "-c:v", "hevc_nvenc",
                        "-profile:v", "main10",
                        "-preset", "p4",
                        "-cq", "18",
                    ]);
                } else {
                    cmd.args([
                        "-c:v", "libx265",
                        "-profile:v", "main10",
                        "-crf", "18",
                        "-preset", "medium",
                        "-pix_fmt", "yuv420p10le",
                    ]);
                }
